#include <bits/stdc++.h>
using namespace std;

// 单哈希模板
struct SingleHash {
    const int base = 131;          // 常用质数: 131, 13331, 10007
    const int mod = 1e9 + 7;       // 常用模数: 1e9+7, 1e9+9, 998244353
    vector<long long> pow, pre;

    void init(const string &s) {
        int n = s.length();
        pow.resize(n + 1);
        pre.resize(n + 1);
        pow[0] = 1;
        for (int i = 1; i <= n; i++) {
            pow[i] = pow[i-1] * base % mod;
            pre[i] = (pre[i-1] * base + s[i-1]) % mod;
        }
    }

    // 获取子串s[l..r]的哈希值 (0-indexed)
    long long get_hash(int l, int r) {
        return (pre[r+1] - pre[l] * pow[r-l+1] % mod + mod) % mod;
    }
};

// 双哈希模板（减少碰撞概率）
struct DoubleHash {
    const int base1 = 131, base2 = 13331;
    const int mod1 = 1e9 + 7, mod2 = 1e9 + 9;
    vector<long long> pow1, pow2, pre1, pre2;

    void init(const string &s) {
        int n = s.length();
        pow1.resize(n + 1);
        pow2.resize(n + 1);
        pre1.resize(n + 1);
        pre2.resize(n + 1);
        pow1[0] = pow2[0] = 1;
        for (int i = 1; i <= n; i++) {
            pow1[i] = pow1[i-1] * base1 % mod1;
            pow2[i] = pow2[i-1] * base2 % mod2;
            pre1[i] = (pre1[i-1] * base1 + s[i-1]) % mod1;
            pre2[i] = (pre2[i-1] * base2 + s[i-1]) % mod2;
        }
    }

    pair<long long, long long> get_hash(int l, int r) {
        long long h1 = (pre1[r+1] - pre1[l] * pow1[r-l+1] % mod1 + mod1) % mod1;
        long long h2 = (pre2[r+1] - pre2[l] * pow2[r-l+1] % mod2 + mod2) % mod2;
        return {h1, h2};
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;

    // 使用示例
    DoubleHash dh;
    dh.init(s);

    // 比较子串是否相等
    int l1, r1, l2, r2;
    cin >> l1 >> r1 >> l2 >> r2;
    if (dh.get_hash(l1, r1) == dh.get_hash(l2, r2)) {
        cout << "Substrings are equal\n";
    }

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// KMP算法：计算next数组
vector<int> getNext(const string &pattern) {
    int n = pattern.size();
    vector<int> next(n, 0);
    for (int i = 1, j = 0; i < n; i++) {
        while (j > 0 && pattern[i] != pattern[j]) {
            j = next[j - 1];
        }
        if (pattern[i] == pattern[j]) {
            j++;
        }
        next[i] = j;
    }
    return next;
}

// KMP算法：在文本中搜索模式串
vector<int> kmpSearch(const string &text, const string &pattern) {
    vector<int> next = getNext(pattern);
    vector<int> positions;
    int n = text.size(), m = pattern.size();

    for (int i = 0, j = 0; i < n; i++) {
        while (j > 0 && text[i] != pattern[j]) {
            j = next[j - 1];
        }
        if (text[i] == pattern[j]) {
            j++;
        }
        if (j == m) {
            positions.push_back(i - m + 1); // 记录匹配起始位置
            j = next[j - 1]; // 继续寻找下一个匹配
        }
    }
    return positions;
}

// 计算字符串的最小周期长度
int minPeriod(const string &s) {
    int n = s.size();
    vector<int> next = getNext(s);
    int period = n - next[n - 1];
    return (n % period == 0) ? period : n;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 示例：KMP基本用法
    string text, pattern;
    cin >> text >> pattern;

    vector<int> matches = kmpSearch(text, pattern);
    cout << "匹配位置：";
    for (int pos : matches) {
        cout << pos << " ";
    }
    cout << endl;

    // 示例：计算最小周期
    string s;
    cin >> s;
    cout << "最小周期长度：" << minPeriod(s) << endl;

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const int ALPHABET_SIZE = 26; // 根据字符集调整

struct TrieNode {
    TrieNode* children[ALPHABET_SIZE];
    bool isEndOfWord;          // 标记单词结束
    int count;                 // 统计前缀出现次数

    TrieNode() {
        isEndOfWord = false;
        count = 0;
        for (int i = 0; i < ALPHABET_SIZE; i++) {
            children[i] = nullptr;
        }
    }
};

class Trie {
private:
    TrieNode* root;

    int charToIndex(char ch) {
        return ch - 'a'; // 小写字母映射
    }

public:
    Trie() {
        root = new TrieNode();
    }

    // 插入字符串
    void insert(const string& word) {
        TrieNode* node = root;
        for (char ch : word) {
            int index = charToIndex(ch);
            if (!node->children[index]) {
                node->children[index] = new TrieNode();
            }
            node = node->children[index];
            node->count++; // 前缀计数增加
        }
        node->isEndOfWord = true;
    }

    // 搜索完整单词
    bool search(const string& word) {
        TrieNode* node = root;
        for (char ch : word) {
            int index = charToIndex(ch);
            if (!node->children[index]) {
                return false;
            }
            node = node->children[index];
        }
        return node->isEndOfWord;
    }

    // 统计前缀出现次数
    int countPrefix(const string& prefix) {
        TrieNode* node = root;
        for (char ch : prefix) {
            int index = charToIndex(ch);
            if (!node->children[index]) {
                return 0;
            }
            node = node->children[index];
        }
        return node->count;
    }

    // 删除字符串（可选实现）
    void remove(const string& word) {
        if (!search(word)) return;
        TrieNode* node = root;
        for (char ch : word) {
            int index = charToIndex(ch);
            node = node->children[index];
            node->count--;
        }
        node->isEndOfWord = false;
    }
};

int main() {
    Trie trie;
    // 示例用法
    trie.insert("apple");
    trie.insert("app");
    cout << trie.search("app") << endl;      // 1
    cout << trie.countPrefix("app") << endl; // 2
    return 0;
}

// 后缀数组模板 (倍增法)
#include <bits/stdc++.h>
using namespace std;

const int N = 1e6 + 10;
char s[N];
int n, m;
int sa[N], rk[N], height[N];
int oldrk[N << 1], id[N], cnt[N];

void buildSA() {
    m = 256;
    for (int i = 1; i <= n; i++) cnt[rk[i] = s[i]]++;
    for (int i = 1; i <= m; i++) cnt[i] += cnt[i - 1];
    for (int i = n; i >= 1; i--) sa[cnt[rk[i]]--] = i;

    for (int w = 1; w < n; w <<= 1) {
        memset(cnt, 0, sizeof(cnt));
        for (int i = 1; i <= n; i++) id[i] = sa[i];
        for (int i = 1; i <= n; i++) cnt[rk[id[i] + w]]++;
        for (int i = 1; i <= m; i++) cnt[i] += cnt[i - 1];
        for (int i = n; i >= 1; i--) sa[cnt[rk[id[i] + w]]--] = id[i];

        memset(cnt, 0, sizeof(cnt));
        for (int i = 1; i <= n; i++) id[i] = sa[i];
        for (int i = 1; i <= n; i++) cnt[rk[id[i]]]++;
        for (int i = 1; i <= m; i++) cnt[i] += cnt[i - 1];
        for (int i = n; i >= 1; i--) sa[cnt[rk[id[i]]]--] = id[i];

        memcpy(oldrk, rk, sizeof(rk));
        int p = 0;
        for (int i = 1; i <= n; i++) {
            if (oldrk[sa[i]] == oldrk[sa[i - 1]] && 
                oldrk[sa[i] + w] == oldrk[sa[i - 1] + w]) {
                rk[sa[i]] = p;
            } else {
                rk[sa[i]] = ++p;
            }
        }
        m = p;
        if (m == n) break;
    }
}

void getHeight() {
    for (int i = 1, k = 0; i <= n; i++) {
        if (k) k--;
        while (s[i + k] == s[sa[rk[i] - 1] + k]) k++;
        height[rk[i]] = k;
    }
}

int main() {
    scanf("%s", s + 1);
    n = strlen(s + 1);
    buildSA();
    getHeight();
    // 输出后缀数组
    for (int i = 1; i <= n; i++) printf("%d ", sa[i]);
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1e6 + 5;
const int ALPHABET = 26;

struct AC_Automaton {
    int tr[MAXN][ALPHABET];
    int fail[MAXN];
    int cnt[MAXN]; // 记录模式串出现次数
    int idx; // 节点编号

    void init() {
        memset(tr[0], 0, sizeof(tr[0]));
        memset(cnt, 0, sizeof(cnt));
        idx = 0;
    }

    void insert(const string &s) {
        int p = 0;
        for (char ch : s) {
            int c = ch - 'a';
            if (!tr[p][c]) {
                tr[p][c] = ++idx;
                memset(tr[idx], 0, sizeof(tr[idx]));
            }
            p = tr[p][c];
        }
        cnt[p]++; // 模式串终点标记
    }

    void build() {
        queue<int> q;
        for (int i = 0; i < ALPHABET; i++) {
            if (tr[0][i]) {
                fail[tr[0][i]] = 0;
                q.push(tr[0][i]);
            }
        }

        while (!q.empty()) {
            int u = q.front();
            q.pop();

            for (int i = 0; i < ALPHABET; i++) {
                if (tr[u][i]) {
                    fail[tr[u][i]] = tr[fail[u]][i];
                    q.push(tr[u][i]);
                } else {
                    tr[u][i] = tr[fail[u]][i];
                }
            }
            // 如果需要累加所有后缀模式串的贡献
            // cnt[u] += cnt[fail[u]];
        }
    }

    int query(const string &s) {
        int p = 0, res = 0;
        for (char ch : s) {
            p = tr[p][ch - 'a'];
            // 遍历所有后缀模式串
            for (int j = p; j && cnt[j] != -1; j = fail[j]) {
                res += cnt[j];
                cnt[j] = -1; // 防止重复计数
            }
        }
        return res;
    }
} ac;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    ac.init();

    for (int i = 0; i < n; i++) {
        string s;
        cin >> s;
        ac.insert(s);
    }

    ac.build();

    string text;
    cin >> text;
    cout << ac.query(text) << endl;

    return 0;
}

// Manacher算法模板
vector<int> manacher(string s) {
    string t = "#";
    for (char c : s) {
        t += c;
        t += '#';
    }
    int n = t.size();
    vector<int> p(n, 0);
    int center = 0, right = 0;
    for (int i = 1; i < n; i++) {
        int mirror = 2 * center - i;
        if (i < right) {
            p[i] = min(right - i, p[mirror]);
        }
        while (i + p[i] + 1 < n && i - p[i] - 1 >= 0 && t[i + p[i] + 1] == t[i - p[i] - 1]) {
            p[i]++;
        }
        if (i + p[i] > right) {
            center = i;
            right = i + p[i];
        }
    }
    return p;
}

// 回文自动机模板
struct PalindromicTree {
    struct Node {
        int len, link;
        map<char, int> next;
        int cnt; // 出现次数
    };
    vector<Node> tree;
    string s;
    int last, size;

    PalindromicTree(string str) : s(str) {
        tree.resize(str.size() + 3);
        tree[0].len = -1; tree[0].link = 0;
        tree[1].len = 0; tree[1].link = 0;
        last = 1;
        size = 2;
        for (int i = 0; i < s.size(); i++) {
            addChar(i);
        }
    }

    void addChar(int pos) {
        char c = s[pos];
        int cur = last;
        while (true) {
            int curLen = tree[cur].len;
            if (pos - curLen - 1 >= 0 && s[pos - curLen - 1] == c) break;
            cur = tree[cur].link;
        }
        if (tree[cur].next.count(c)) {
            last = tree[cur].next[c];
            tree[last].cnt++;
            return;
        }
        int newNode = size++;
        tree[newNode].len = tree[cur].len + 2;
        tree[cur].next[c] = newNode;
        if (tree[newNode].len == 1) {
            tree[newNode].link = 1;
        } else {
            int link = tree[cur].link;
            while (true) {
                int linkLen = tree[link].len;
                if (pos - linkLen - 1 >= 0 && s[pos - linkLen - 1] == c) break;
                link = tree[link].link;
            }
            tree[newNode].link = tree[link].next[c];
        }
        tree[newNode].cnt = 1;
        last = newNode;
    }
};

#include <bits/stdc++.h>
using namespace std;

// Z函数模板
vector<int> z_function(const string &s) {
    int n = (int)s.length();
    vector<int> z(n);
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r)
            z[i] = min(r - i + 1, z[i - l]);
        while (i + z[i] < n && s[z[i]] == s[i + z[i]])
            ++z[i];
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

// 前缀函数模板（KMP）
vector<int> prefix_function(const string &s) {
    int n = (int)s.length();
    vector<int> pi(n);
    for (int i = 1; i < n; ++i) {
        int j = pi[i - 1];
        while (j > 0 && s[i] != s[j])
            j = pi[j - 1];
        if (s[i] == s[j])
            ++j;
        pi[i] = j;
    }
    return pi;
}

// 使用Z函数进行模式匹配
void pattern_matching(const string &text, const string &pattern) {
    string combined = pattern + "#" + text;
    vector<int> z = z_function(combined);
    int m = pattern.length();
    for (int i = m + 1; i < combined.length(); ++i) {
        if (z[i] == m) {
            // 在位置 i-m-1 处找到匹配
            cout << "Found at index: " << i - m - 1 << endl;
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;

    // 计算Z函数
    vector<int> z = z_function(s);

    // 输出结果
    for (int i = 0; i < z.size(); ++i) {
        cout << z[i] << " ";
    }
    cout << endl;

    return 0;
}
